import hashlib
from datetime import date

class Account:
    def __init__(self, account_number, balance=0):
        self.account_number = account_number
        self.balance = balance
        self.transactions = []

    def deposit(self, amount, transaction_id=None):
        if transaction_id is None:
            transaction_id = hashlib.sha256(str(date.today()) + str(amount)).hexdigest()
        
        self.balance += amount
        self.transactions.append({
            'type': 'deposit',
            'amount': amount,
            'transaction_id': transaction_id
        })

    def withdraw(self, amount, transaction_id=None):
        if transaction_id is None:
            transaction_id = hashlib.sha256(str(date.today()) + str(amount)).hexdigest()
        
        if self.balance >= amount:
            self.balance -= amount
            self.transactions.append({
                'type': 'withdrawal',
                'amount': amount,
                'transaction_id': transaction_id
            })
        else:
            print("Insufficient balance")

    def get_balance(self):
        return self.balance

def process_transactions(account, transactions):
    for transaction in transactions:
        if transaction['type'] == 'deposit':
            account.deposit(transaction['amount'], transaction['id'])
        elif transaction['type'] == 'withdrawal':
            account.withdraw(transaction['amount'], transaction['id'])

# Example usage
account = Account('1234567890')
transactions = [
    {'type': 'deposit', 'amount': 100, 'id': hashlib.sha256(str(date.today()) + str(100)).hexdigest()},
    {'type': 'withdrawal', 'amount': 50, 'id': hashlib.sha256(str(date.today()) + str(50)).hexdigest()}
]

process_transactions(account, transactions)
print("Account balance:", account.get_balance())